import jwt
import datetime
import uuid
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_super_secret_key_here' # Change this to a strong, random key in production

# In a real application, this would be a database
users = {
    "user1": {"password": "password1"},
    "user2": {"password": "password2"}
}

# In a real application, this would be a persistent store (e.g., Redis, database)
# for invalidating tokens or storing active sessions.
# For this simple example, we'll just store active tokens.
active_tokens = {}

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        if 'x-access-token' in request.headers:
            token = request.headers['x-access-token']
        if not token:
            return jsonify({'message': 'Token is missing!'}), 401

        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
            current_user_id = data['user_id']
            # Optional: Check if the token is still considered active/valid in our store
            if token not in active_tokens.get(current_user_id, []):
                 return jsonify({'message': 'Token is invalid or expired!'}), 401
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'Token has expired!'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'Token is invalid!'}), 401

        return f(current_user_id, *args, **kwargs)
    return decorated

@app.route('/login', methods=['POST'])
def login():
    auth = request.json
    if not auth or not auth.get('username') or not auth.get('password'):
        return jsonify({'message': 'Could not verify', 'WWW-Authenticate': 'Basic realm="Login required!"'}), 401

    username = auth.get('username')
    password = auth.get('password')

    user = users.get(username)

    if not user or user['password'] != password:
        return jsonify({'message': 'Could not verify', 'WWW-Authenticate': 'Basic realm="Login required!"'}), 401

    # Generate a unique token ID for this session
    token_id = str(uuid.uuid4())

    token = jwt.encode({
        'user_id': username,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30), # Token expires in 30 minutes
        'iat': datetime.datetime.utcnow(),
        'jti': token_id # JWT ID
    }, app.config['SECRET_KEY'], algorithm="HS256")

    # Store the token as active for the user
    if username not in active_tokens:
        active_tokens[username] = []
    active_tokens[username].append(token)

    return jsonify({'token': token})

@app.route('/protected', methods=['GET'])
@token_required
def protected(current_user_id):
    return jsonify({'message': f'Hello, {current_user_id}! This is a protected endpoint.'})

@app.route('/logout', methods=['POST'])
@token_required
def logout(current_user_id):
    token = request.headers.get('x-access-token')
    if token and current_user_id in active_tokens and token in active_tokens[current_user_id]:
        active_tokens[current_user_id].remove(token)
        return jsonify({'message': 'Successfully logged out.'}), 200
    return jsonify({'message': 'Failed to logout or token not found.'}), 400

if __name__ == '__main__':
    app.run(debug=True)